import { ref, computed, watch, nextTick, reactive, inject, onBeforeUnmount, onMounted, watchEffect, onScopeDispose, shallowReactive } from 'vue-demi';
import { getElById, getNodePath, replaceChildNode, isPage, isDslNode, toLine } from '@tmagic/core';

const useEditorDsl = (app = inject("app"), win = window) => {
  const root = ref();
  const curPageId = ref();
  const selectedId = ref();
  const pageConfig = computed(
    () => root.value?.items?.find((item) => item.id === curPageId.value) || root.value?.items?.[0]
  );
  watch(pageConfig, async () => {
    await nextTick();
    const page = document.querySelector(".magic-ui-page");
    page && win.magic?.onPageElUpdate(page);
  });
  win.magic?.onRuntimeReady({
    getApp() {
      return app;
    },
    updateRootConfig(config) {
      root.value = config;
      if (typeof curPageId.value === "undefined") {
        curPageId.value = config.items?.[0]?.id;
      }
      if (typeof selectedId.value === "undefined") {
        selectedId.value = curPageId.value;
      }
      app?.setConfig(config, curPageId.value);
    },
    updatePageId(id) {
      curPageId.value = id;
      app?.setPage(id);
    },
    select(id) {
      selectedId.value = id;
      if (app?.getPage(id)) {
        this.updatePageId?.(id);
      }
      const el = getElById()(document, `${id}`);
      if (el) return el;
      return nextTick().then(() => getElById()(document, `${id}`));
    },
    add({ config, parentId }) {
      if (!root.value) throw new Error("error");
      if (!selectedId.value) throw new Error("error");
      if (!parentId) throw new Error("error");
      const parent = getNodePath(parentId, [root.value]).pop();
      if (!parent) throw new Error("未找到父节点");
      if (config.type !== "page") {
        const parentNode = app?.page?.getNode(parent.id);
        parentNode && app?.page?.initNode(config, parentNode);
      }
      if (parent.id !== selectedId.value) {
        const index = parent.items?.findIndex((child) => child.id === selectedId.value);
        parent.items?.splice(index + 1, 0, config);
      } else {
        parent.items?.push(config);
      }
    },
    update({ config, parentId }) {
      if (!root.value || !app) throw new Error("error");
      const newNode = app.dataSourceManager?.compiledNode(config, undefined, true) || config;
      replaceChildNode(reactive(newNode), [root.value], parentId);
      const nodeInstance = app.getNode(config.id);
      if (nodeInstance) {
        nodeInstance.setData(newNode);
      }
      if (app.page?.data.id === config.id) {
        app.page.setData(newNode);
      }
    },
    remove({ id, parentId }) {
      if (!root.value) throw new Error("error");
      const node = getNodePath(id, [root.value]).pop();
      if (!node) throw new Error("未找到目标元素");
      const parent = getNodePath(parentId, [root.value]).pop();
      if (!parent) throw new Error("未找到父元素");
      if (node.type === "page") {
        app?.deletePage();
      } else {
        app?.page?.deleteNode(node.id);
      }
      const index = parent.items?.findIndex((child) => child.id === node.id);
      parent.items.splice(index, 1);
    }
  });
  return {
    pageConfig,
    app
  };
};

const useDsl = (app = inject("app")) => {
  if (!app) {
    throw new Error("useDsl must be used after MagicApp is created");
  }
  const pageConfig = ref(app.page?.data || {});
  app.on("page-change", () => {
    pageConfig.value = app.page?.data || {};
  });
  const updateDataHandler = (nodes, sourceId, changeEvent) => {
    nodes.forEach((node) => {
      if (isPage(node)) {
        pageConfig.value = node;
      } else {
        replaceChildNode(reactive(node), [pageConfig.value]);
      }
    });
    nextTick(() => {
      app.emit("replaced-node", { nodes, sourceId, ...changeEvent });
    });
  };
  if (app.dataSourceManager) {
    app.dataSourceManager.on("update-data", updateDataHandler);
    onBeforeUnmount(() => {
      app.dataSourceManager.off("update-data", updateDataHandler);
    });
  }
  return {
    app,
    pageConfig
  };
};

const useNode = (props, app = inject("app")) => isDslNode(props.config) && props.config.id ? app?.getNode(props.config.id, props.iteratorContainerId, props.iteratorIndex) : undefined;
const registerNodeHooks = (node, methods = {}) => {
  if (!node) {
    return;
  }
  const emitData = {
    config: node.data,
    ...methods
  };
  node.emit("created", emitData);
  onMounted(() => {
    node.emit("mounted", emitData);
  });
  onBeforeUnmount(() => {
    node.emit("destroy", emitData);
  });
};
const useApp = ({
  methods = {},
  config,
  iteratorContainerId,
  iteratorIndex
}) => {
  const app = inject("app");
  const node = useNode(
    {
      config,
      iteratorContainerId,
      iteratorIndex
    },
    app
  );
  if (node) {
    registerNodeHooks(node, methods);
  }
  return {
    app,
    node
  };
};

const useComponentStatus = (props) => {
  const app = inject("app");
  const status = ref("default");
  const styleStatusMap = /* @__PURE__ */ new Map();
  const classStatusMap = /* @__PURE__ */ new Map();
  const statusMap = /* @__PURE__ */ new Map();
  const setStatus = (value) => {
    status.value = value;
  };
  const registerStatus = (type, { style, className, ...data }) => {
    if (style) {
      styleStatusMap.set(type, style);
    }
    if (className) {
      classStatusMap.set(type, className);
    }
    statusMap.set(type, shallowReactive(data));
  };
  watchEffect(() => {
    registerStatus("default", {
      style: props.config.style,
      className: props.config.className
    });
  });
  onScopeDispose(() => {
    statusMap.clear();
  });
  return {
    status: computed(() => status.value),
    style: computed(() => {
      const type = status.value || "default";
      const defaultStyle = styleStatusMap.get("default") || {};
      const statusStyle = styleStatusMap.get(type);
      let style = app?.transformStyle(defaultStyle) || {};
      if (type !== "default" && statusStyle) {
        style = Object.keys(statusStyle).reduce((obj, key) => {
          const value = statusStyle[key];
          if (value === null || typeof value === "undefined" || isNaN(value) || value === "") {
            return {
              ...obj,
              [key]: statusStyle[key]
            };
          }
          return { ...obj };
        }, style);
      }
      if (props.config.displayHidden) {
        style.display = "none";
      }
      if (typeof props.config.condResult !== "undefined" && props.config.displayRenderModel === "mount") {
        if (props.config.condResult === false) {
          style.display = "none";
        }
      }
      return style;
    }),
    className: computed(() => {
      const type = status.value || "default";
      const className = classStatusMap.get(type) ?? "";
      const list = [];
      if (props.config.type) {
        list.push(`magic-ui-${toLine(props.config.type)}`);
      }
      if (props.config.layout) {
        list.push(`magic-layout-${props.config.layout}`);
      }
      if (className) {
        list.push(className);
      }
      return list.join(" ");
    }),
    setStatus,
    registerStatus
  };
};

function useComponent(options = "") {
  let componentType;
  let app;
  let component;
  if (typeof options === "string") {
    componentType = options;
  } else {
    ({ componentType, app } = options);
  }
  if (!componentType || componentType === "") {
    componentType = "container";
  }
  if (!app) {
    app = inject("app");
  }
  component = resolveComponent({ componentType, app });
  if (!component && !componentType.startsWith("magic-ui-")) {
    componentType = `magic-ui-${toLine(componentType)}`;
    component = resolveComponent({ componentType, app });
  }
  return component ?? componentType;
}
function resolveComponent({ componentType, app }) {
  return app?.resolveComponent(componentType);
}

export { registerNodeHooks, useApp, useComponent, useComponentStatus, useDsl, useEditorDsl, useNode };
